    validateParams: (segments, params) => {
      const sanitizedParams = {};
      if (params.section) {
        const section = sanitizeParam(params.section);
        if (['general', 'notifications', 'privacy', 'account'].includes(section)) {
          sanitizedParams.section = section;
        }
      }
      return sanitizedParams;
    },
