// Resolve parsed URL to navigation action
const resolveNavigation = (parsed) => {
  if (!parsed) return null;

  const routeConfig = ROUTE_CONFIG[parsed.host];
  if (!routeConfig) return null;

  // Handle sub-routes (e.g., payment/confirm)
  if (routeConfig.subRoutes) {
    const subPath = parsed.segments[1];
    if (!subPath) return null;

    const subRoute = routeConfig.subRoutes[subPath.toLowerCase()];
    if (!subRoute) {
      console.warn(`Unknown sub-route: ${parsed.host}/${subPath}`);
      return null;
    }

    const validatedParams = subRoute.validateParams(parsed.segments, parsed.params);
    if (validatedParams === null) return null;

    return {
      screen: subRoute.screen,
      params: validatedParams,
    };
  }

  // Handle direct routes
  const validatedParams = routeConfig.validateParams(parsed.segments, parsed.params);
  if (validatedParams === null) {
    console.warn(`Invalid parameters for route: ${parsed.host}`);
    return null;
  }

  return {
    screen: routeConfig.screen,
    params: validatedParams,
  };
};

// Rate limiting for deep link handling
const createRateLimiter = (maxRequests = 5, windowMs = 10000) => {
  const timestamps = [];

  return () => {
    const now = Date.now();
    // Remove expired timestamps
    while (timestamps.length > 0 && timestamps[0] < now - windowMs) {
      timestamps.shift();
    }
    if (timestamps.length >= maxRequests) {
      console.warn('Deep link rate limit exceeded');
      return false;
    }
    timestamps.push(now);
    return true;
  };
};

