// ---- Deep Link Handler Hook ----

const useDeepLinkHandler = () => {
  const rateLimiter = useRef(createRateLimiter()).current;
  const processedUrls = useRef(new Set());

  const handleDeepLink = useCallback(
    (url) => {
      if (!url) return;

      // Prevent duplicate processing
      const urlKey = `${url}_${Math.floor(Date.now() / 1000)}`;
      if (processedUrls.current.has(urlKey)) return;
      processedUrls.current.add(urlKey);

      // Clean up old entries
      if (processedUrls.current.size > 100) {
        const entries = Array.from(processedUrls.current);
        processedUrls.current = new Set(entries.slice(-50));
      }

      // Rate limiting
      if (!rateLimiter()) {
        Alert.alert('Too Many Requests', 'Please try again in a moment.');
        return;
      }

      console.log('Processing deep link:', url);

      // Parse the URL
      const parsed = parseDeepLink(url);
      if (!parsed) {
        console.warn('Invalid or blocked deep link:', url);
        return;
      }

      // Resolve to navigation action
      const navAction = resolveNavigation(parsed);
      if (!navAction) {
        console.warn('Could not resolve navigation for:', url);
        if (navigationRef.current?.isReady()) {
          navigationRef.current.navigate('NotFound');
        }
        return;
      }

      // Navigate
      if (navigationRef.current?.isReady()) {
        console.log(`Navigating to ${navAction.screen} with params:`, navAction.params);
        navigationRef.current.navigate(navAction.screen, navAction.params);
      } else {
        console.warn('Navigation not ready, queuing deep link');
        // Retry after a short delay
        setTimeout(() => {
          if (navigationRef.current?.isReady()) {
            navigationRef.current.navigate(navAction.screen, navAction.params);
          }
        }, 1000);
      }
    },
    [rateLimiter]
  );

  return handleDeepLink;
};

// ---- Stack Navigator ----

const Stack = createNativeStackNavigator();

