// ---- Utility: Handle push notification deep links ----
// Call this from your push notification handler
export const handlePushNotificationDeepLink = (notificationData) => {
  if (!notificationData || !notificationData.deepLink) return;

  const url = notificationData.deepLink;

  // Validate it's a string
  if (typeof url !== 'string') return;

  // Ensure it uses our scheme
  if (!url.startsWith('myapp://')) {
    console.warn('Push notification contains non-app deep link, ignoring');
    return;
  }

  // Use Linking to trigger the deep link handler
  Linking.openURL(url).catch((err) => {
    console.error('Failed to open deep link from push notification:', err.message);
  });
};

// ---- Utility: Generate deep links for marketing campaigns ----
export const generateDeepLink = (screen, params = {}) => {
  switch (screen) {
    case 'profile': {
      const id = validateNumericId(String(params.userId));
      if (!id) throw new Error('Invalid user ID');
      return `myapp://profile/${id}`;
    }
    case 'paymentConfirm': {
      let url = 'myapp://payment/confirm';
      const queryParts = [];
      if (params.transactionId) {
        const txId = sanitizeParam(params.transactionId);
        if (/^[a-zA-Z0-9_-]+$/.test(txId)) {
          queryParts.push(`transactionId=${encodeURIComponent(txId)}`);
        }
      }
      if (params.amount) {
        const amount = parseFloat(params.amount);
        if (!isNaN(amount) && amount > 0) {
          queryParts.push(`amount=${amount}`);
        }
      }
      if (queryParts.length > 0) {
        url += '?' + queryParts.join('&');
      }
      return url;
    }
    case 'settings': {
      let url = 'myapp://settings';
      if (params.section) {
        const section = sanitizeParam(params.section);
        if (['general', 'notifications', 'privacy', 'account'].includes(section)) {
          url += `?section=${encodeURIComponent(section)}`;
        }
      }
      return url;
    }
    case 'home':
      return 'myapp://home';
    default:
      throw new Error(`Unknown screen: ${screen}`);
  }
};

